solutions.python:
class Solution:
  def fix_box_model(self, styles):
    styles_list = styles.split('}')
    for i, style in enumerate(styles_list):
      box_sizing_value = style.split('box-sizing:')[1].split(';')[0].trim()
      if box_sizing_value != 'border-box' and box_sizing_value != 'content-box':
        styles_list[i] = style.replace(box_sizing_value, 'border-box')
    return '}'.join(styles_list)
